"""Tests for session-level cost aggregation across multiple processes.

Per the Claude API, cost_usd is cumulative-per-process. SDK resume flows
share a session_id across many distinct processes; the session view
exposes total + daily spend across all of them.
"""

from pathlib import Path

import pytest

from agentpulse.api.v2 import queries
from agentpulse.db import close_db, init_db
from agentpulse.platforms.claude import schema


@pytest.fixture
async def db(tmp_path: Path):
    conn = await init_db(db_path=tmp_path / "test.db")
    yield conn
    await close_db()


async def _seed_hook(
    db,
    *,
    session_id: str,
    pid: int,
    received_at: float,
    cwd: str = "/proj",
    source_system: str = "host",
) -> None:
    payload = {
        "session_id": session_id,
        "hook_event_name": "PreToolUse",
        "pid": pid,
        "source_system": source_system,
        "cwd": cwd,
    }
    await schema.insert_log_hook(
        db, payload=payload, received_at=received_at, received_by="test"
    )
    await db.commit()


async def _seed_statusline(
    db,
    *,
    session_id: str,
    pid: int,
    received_at: float,
    cost_usd: float,
    cwd: str = "/proj",
    source_system: str = "host",
) -> None:
    payload = {
        "session_id": session_id,
        "pid": pid,
        "source_system": source_system,
        "cwd": cwd,
        "cost": {"total_cost_usd": cost_usd},
    }
    await schema.insert_log_statusline(
        db, payload=payload, received_at=received_at, received_by="test"
    )
    await db.commit()


async def _seed_death(
    db,
    *,
    pid: int,
    observed_at: float,
    cwd: str = "/proj",
    source_system: str = "host",
) -> None:
    await schema.insert_log_pid_death(
        db,
        pid=pid,
        source_system=source_system,
        cwd=cwd,
        observed_at=observed_at,
        observed_by="pid-watcher",
    )
    await db.commit()


# 2026-04-21 22:27:43 UTC == 1777152463 — picking timestamps that fall on
# distinct local dates to keep the day buckets predictable across timezones.
DAY1_START = 1777152463.0  # day "D1" in server-local time
DAY2_START = DAY1_START + 86400.0  # day after


class TestSessionTotalCost:
    async def test_single_process_session(self, db) -> None:
        await _seed_hook(db, session_id="s1", pid=10, received_at=DAY1_START)
        await _seed_statusline(
            db, session_id="s1", pid=10, received_at=DAY1_START + 60, cost_usd=2.5
        )
        sess = await queries.get_session_by_id(db, session_id="s1")
        assert sess is not None
        assert sess["total_cost_usd"] == 2.5

    async def test_multi_process_session_sums_cost(self, db) -> None:
        # Three SDK invocations on the same session, distinct pids, each
        # accumulating its own cost counter.
        for pid, cost in [(10, 5.0), (20, 7.5), (30, 1.25)]:
            await _seed_hook(db, session_id="s1", pid=pid, received_at=DAY1_START + pid)
            await _seed_statusline(
                db,
                session_id="s1",
                pid=pid,
                received_at=DAY1_START + pid + 1,
                cost_usd=cost,
            )
        sess = await queries.get_session_by_id(db, session_id="s1")
        # 5.0 + 7.5 + 1.25 = 13.75
        assert sess["total_cost_usd"] == 13.75

    async def test_per_process_max_used_not_sum(self, db) -> None:
        """Cost is monotonic within a process — only the LAST (max) reading
        counts per process. Multiple statuslines from one process don't
        double-count."""
        await _seed_hook(db, session_id="s1", pid=10, received_at=DAY1_START)
        # Three readings from the same process — only the max matters
        for ts_offset, cost in [(60, 1.0), (120, 3.0), (180, 5.0)]:
            await _seed_statusline(
                db,
                session_id="s1",
                pid=10,
                received_at=DAY1_START + ts_offset,
                cost_usd=cost,
            )
        sess = await queries.get_session_by_id(db, session_id="s1")
        assert sess["total_cost_usd"] == 5.0  # max(cost), not sum

    async def test_no_cost_yields_zero(self, db) -> None:
        await _seed_hook(db, session_id="s1", pid=10, received_at=DAY1_START)
        # No statuslines at all
        sess = await queries.get_session_by_id(db, session_id="s1")
        assert sess["total_cost_usd"] == 0.0
        assert sess["cost_by_day"] == {}


class TestSessionCostByDay:
    async def test_single_process_one_day(self, db) -> None:
        await _seed_hook(db, session_id="s1", pid=10, received_at=DAY1_START)
        await _seed_statusline(
            db, session_id="s1", pid=10, received_at=DAY1_START + 60, cost_usd=4.0
        )
        sess = await queries.get_session_by_id(db, session_id="s1")
        # Single day → that day has the full cost
        assert sum(sess["cost_by_day"].values()) == pytest.approx(4.0)
        assert len(sess["cost_by_day"]) == 1

    async def test_single_process_two_days(self, db) -> None:
        # Day 1: cost reaches 3.0. Day 2: same process continues, reaches 5.0.
        # Daily deltas: D1=3.0, D2=2.0. Sum=5.0 = the process's MAX.
        await _seed_hook(db, session_id="s1", pid=10, received_at=DAY1_START)
        await _seed_statusline(
            db, session_id="s1", pid=10, received_at=DAY1_START + 60, cost_usd=3.0
        )
        await _seed_statusline(
            db, session_id="s1", pid=10, received_at=DAY2_START + 60, cost_usd=5.0
        )
        sess = await queries.get_session_by_id(db, session_id="s1")
        cost_by_day = sess["cost_by_day"]
        assert len(cost_by_day) == 2
        days = sorted(cost_by_day.keys())
        assert cost_by_day[days[0]] == pytest.approx(3.0)
        assert cost_by_day[days[1]] == pytest.approx(2.0)

    async def test_multi_process_same_day_sums(self, db) -> None:
        # Two processes spending on the same day: $2 + $3 = $5 for that day.
        await _seed_hook(db, session_id="s1", pid=10, received_at=DAY1_START)
        await _seed_hook(db, session_id="s1", pid=20, received_at=DAY1_START + 5)
        await _seed_statusline(
            db, session_id="s1", pid=10, received_at=DAY1_START + 60, cost_usd=2.0
        )
        await _seed_statusline(
            db, session_id="s1", pid=20, received_at=DAY1_START + 120, cost_usd=3.0
        )
        sess = await queries.get_session_by_id(db, session_id="s1")
        assert len(sess["cost_by_day"]) == 1
        (day_total,) = sess["cost_by_day"].values()
        assert day_total == pytest.approx(5.0)

    async def test_multi_process_multi_day(self, db) -> None:
        # Process A: day1 costs $2, total stays $2. Day2 it dies before reading.
        # Process B: starts on day2, costs $3.
        # Expected: day1=$2, day2=$3. Total=$5.
        await _seed_hook(db, session_id="s1", pid=10, received_at=DAY1_START)
        await _seed_statusline(
            db, session_id="s1", pid=10, received_at=DAY1_START + 60, cost_usd=2.0
        )
        await _seed_hook(db, session_id="s1", pid=20, received_at=DAY2_START)
        await _seed_statusline(
            db, session_id="s1", pid=20, received_at=DAY2_START + 60, cost_usd=3.0
        )
        sess = await queries.get_session_by_id(db, session_id="s1")
        days = sorted(sess["cost_by_day"].keys())
        assert len(days) == 2
        assert sess["cost_by_day"][days[0]] == pytest.approx(2.0)
        assert sess["cost_by_day"][days[1]] == pytest.approx(3.0)
        assert sess["total_cost_usd"] == pytest.approx(5.0)

    async def test_concurrent_processes_cost_independent(self, db) -> None:
        """Two processes running concurrently in the same cwd accumulate
        independent cost counters. Session daily total = sum across them.
        """
        await _seed_hook(db, session_id="s1", pid=10, received_at=DAY1_START)
        await _seed_hook(db, session_id="s1", pid=20, received_at=DAY1_START + 30)
        # Both processes report on the same day. P10 hits $4, P20 hits $1.5.
        await _seed_statusline(
            db, session_id="s1", pid=10, received_at=DAY1_START + 100, cost_usd=4.0
        )
        await _seed_statusline(
            db, session_id="s1", pid=20, received_at=DAY1_START + 110, cost_usd=1.5
        )
        sess = await queries.get_session_by_id(db, session_id="s1")
        (day_total,) = sess["cost_by_day"].values()
        assert day_total == pytest.approx(5.5)
        assert sess["total_cost_usd"] == pytest.approx(5.5)


class TestPidReuseAggregation:
    """When a pid is reused within the same session (rare — OS reassigns
    the same pid to a new Claude Code process after the prior one died,
    and the user resumes that session into the new process), the two
    instances each have their own cost counter. Instance-windowed grouping
    by claude_log_pid_deaths must split them apart.
    """

    async def test_total_cost_sums_reused_pid_instances(self, db) -> None:
        # Instance 1: pid=10 reaches $7, dies on day 1
        await _seed_hook(db, session_id="s1", pid=10, received_at=DAY1_START)
        await _seed_statusline(
            db, session_id="s1", pid=10, received_at=DAY1_START + 60, cost_usd=7.0
        )
        await _seed_death(db, pid=10, observed_at=DAY1_START + 100)
        # Instance 2: same pid reused, reaches $4 on day 2
        await _seed_hook(db, session_id="s1", pid=10, received_at=DAY2_START)
        await _seed_statusline(
            db, session_id="s1", pid=10, received_at=DAY2_START + 60, cost_usd=4.0
        )

        sess = await queries.get_session_by_id(db, session_id="s1")
        # Without instance windowing this would collapse to MAX(7, 4) = 7
        assert sess["total_cost_usd"] == pytest.approx(11.0)

    async def test_cost_by_day_splits_reused_pid_instances(self, db) -> None:
        # Same scenario as above but check the daily breakdown
        await _seed_hook(db, session_id="s1", pid=10, received_at=DAY1_START)
        await _seed_statusline(
            db, session_id="s1", pid=10, received_at=DAY1_START + 60, cost_usd=7.0
        )
        await _seed_death(db, pid=10, observed_at=DAY1_START + 100)
        await _seed_hook(db, session_id="s1", pid=10, received_at=DAY2_START)
        await _seed_statusline(
            db, session_id="s1", pid=10, received_at=DAY2_START + 60, cost_usd=4.0
        )

        sess = await queries.get_session_by_id(db, session_id="s1")
        days = sorted(sess["cost_by_day"].keys())
        assert len(days) == 2
        # Each instance contributes its full cost to its own day.
        assert sess["cost_by_day"][days[0]] == pytest.approx(7.0)
        assert sess["cost_by_day"][days[1]] == pytest.approx(4.0)


